    static int mod(int a)
    {
        int t = a - HQCParameters.GF_MUL_ORDER;
//        return t + ((t >> 31) & HQCParameters.GF_MUL_ORDER);
        return t + (t >>> 24);
    }

    static int mul(int a, int b)
    {
        int ma = -a >> 31; // a != 0
        int mb = -b >> 31; // b != 0
        return ma & mb & _EXP[mod(_LOG[a] + _LOG[b])];
    }

